+/**
+ * Run a delegated agent without exposing its stream directly. Its text is returned to
+ * the caller as the content of the delegating agent's tool_result.
+ */
+async function collectDelegatedAgentOutput(
+  agentId: string,
+  instructions: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: readonly string[],
+): Promise<DelegationResult> {
+  if (delegationPath.includes(agentId)) {
+    const message = `Circular delegation detected for agent '${agentId}'`;
+    return { content: message, isError: true, streamError: message };
+  }
+
+  if (!globalRegistry.getAgent(agentId) || !globalRegistry.getProviderForAgent(agentId)) {
+    const message = `Agent '${agentId}' not found or provider not available`;
+    return { content: message, isError: true, streamError: message };
+  }
+
+  const delegatedRequest: ChatRequest = {
+    ...request,
+    message: instructions,
+  };
+  const text: string[] = [];
+
+  try {
+    for await (const response of executeSingleAgent(
+      agentId,
+      delegatedRequest,
+      null,
+      abortController,
+      debugMode,
+      [...delegationPath],
+    )) {
+      const output = textFromStreamResponse(response);
+      if (output) text.push(output);
+
+      if (response.type === "error") {
+        return {
+          content: response.error || `Sub-agent '${agentId}' failed`,
+          isError: true,
+        };
+      }
+    }
+  } catch (error) {
+    return {
+      content: error instanceof Error ? error.message : String(error),
+      isError: true,
+    };
+  }
+
+  return {
+    content: text.join("") || "Delegated agent completed without producing text.",
+    isError: false,
+  };
