+async function collectDelegatedAgentOutput(
+  agentId: string,
+  instructions: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: readonly string[],
+): Promise<DelegationResult> {
+  if (delegationPath.includes(agentId)) {
+    const message = `Circular delegation detected for agent '${agentId}'`;
+    return { content: message, isError: true, streamError: message };
+  }
